document.addEventListener("DOMContentLoaded",()=>{async function handleFormSubmit(e){const t=e.currentTarget,n=t.getAttribute("data-url"),a=t.getAttribute("data-message"),l={},o=[];document.querySelectorAll(".card-body").forEach(e=>{e.querySelectorAll("input, select, textarea").forEach(e=>{if("INPUT"===e.tagName)if("checkbox"===e.type)l[e.name]=e.checked;else if("date"===e.type)l[e.name]=""===e.value?null:new Date(e.value);else if("file"===e.type&&e.files.length>0){const t=new Promise((t,n)=>{const a=new FileReader;a.onload=function(n){l[e.name]=n.target.result,t()},a.onerror=n,a.readAsDataURL(e.files[0])});o.push(t)}else l[e.name]=e.value;else if("TEXTAREA"===e.tagName)l[e.name]=e.value;else if("SELECT"===e.tagName)if(e.multiple){const t=Array.from(e.selectedOptions).map(e=>e.value);l[e.name]=t.length>0?t:[]}else l[e.name]=-1===e.selectedIndex?null:e.options[e.selectedIndex].value})});try{await Promise.all(o);const e=await fetch(n,{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify(l)});if(!e.ok)throw new Error(`HTTP error! status: ${e.status}`);const t=await e.json();t.success&&Swal.fire({icon:"success",title:" ",html:`\n            <ul>\n              <li class="fw600">${a}</li>\n            </ul>\n          `,timer:2500,confirmButtonText:"Κλείσιμο",customClass:{confirmButton:"class-success custom-confirm-button custom-swal-button"}}).then(()=>{window.location.href=t.redirectUrl})}catch(e){console.log("Σφάλμα:",e)}}document.querySelectorAll(".submitButton").forEach(e=>{e.addEventListener("click",handleFormSubmit)})});